from agents.basic_agent import BasicAgent


class WeatherAgent(BasicAgent):
    """Sample custom agent shipped with kodyTwinAI."""

    def __init__(self):
        self.name = 'Weather'
        self.metadata = {
            "name": self.name,
            "description": "Report the weather for a city. Demo agent — returns deterministic mock data.",
            "parameters": {
                "type": "object",
                "properties": {"city": {"type": "string"}},
                "required": ["city"]
            }
        }
        super().__init__(name=self.name, metadata=self.metadata)

    def perform(self, **kwargs):
        city = kwargs.get('city', 'unknown')
        import hashlib
        h = int(hashlib.md5(city.lower().encode()).hexdigest(), 16)
        temp = 50 + (h % 40)
        conds = ["sunny", "partly cloudy", "overcast", "light rain"][(h >> 8) % 4]
        wind = ["calm", "light breeze", "breezy"][(h >> 16) % 3]
        return f"The weather in {city} is {temp}F, {conds}, with {wind} winds. (Demo data from kodyTwinAI's bundled Weather agent.)"
